import { useTranslation } from "react-i18next";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { formatDistanceToNow, format } from "date-fns";
import { Mail, Phone, Store, MapPin, Download, Search, Trash2, Filter, Send, Eye, Ticket, UserCircle, Clock, CheckCircle2, XCircle, Archive, MoreHorizontal } from "lucide-react";
import { useState, useEffect } from "react";
import { toast } from "@/hooks/use-toast";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";

const STATUS_OPTIONS = ["pending", "received", "completed", "cancelled"] as const;
const TAX_STATUS_OPTIONS = ["all", "manual_review", "verified", "rejected"] as const;

const AdminJoinRequests = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState<string>("owner");
  const [showArchived, setShowArchived] = useState(false);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [taxStatusFilter, setTaxStatusFilter] = useState<string>("all");
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [emailDialogOpen, setEmailDialogOpen] = useState(false);
  const [detailDialogOpen, setDetailDialogOpen] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<any>(null);
  const [merchantAccount, setMerchantAccount] = useState("");
  const [merchantPassword, setMerchantPassword] = useState("");
  const [sendingEmail, setSendingEmail] = useState(false);
  const [creatingUser, setCreatingUser] = useState(false);
  const [emailOnlyMode, setEmailOnlyMode] = useState(false);
  const [approvingId, setApprovingId] = useState<string | null>(null);
  const queryClient = useQueryClient();

  // Fetch helper to enrich join requests with inviter profiles and filter out admins
  const fetchJoinRequests = async (isOwnStore: boolean) => {
    let query = supabase
      .from("join_requests")
      .select("*")
      .order("created_at", { ascending: false });

    if (isOwnStore) {
      query = query.eq("is_own_store", true).not("existing_user_id", "is", null);
    } else {
      query = query.or("is_own_store.is.null,is_own_store.eq.false");
    }

    const { data, error } = await query;
    if (error) throw error;

    // Exclude admin/supervisor users
    const userIds = [...new Set((data || []).map(r => r.existing_user_id).filter(Boolean))];
    let adminUserIds = new Set<string>();
    if (userIds.length > 0) {
      const { data: roles } = await supabase
        .from("user_roles")
        .select("user_id, role")
        .in("user_id", userIds)
        .in("role", ["admin", "supervisor"]);
      if (roles) adminUserIds = new Set(roles.map(r => r.user_id));
    }
    const filteredData = (data || []).filter(r => !r.existing_user_id || !adminUserIds.has(r.existing_user_id));

    // Get inviter profile names
    const inviterIds = filteredData.map(r => r.invited_by_user_id).filter(Boolean) || [];
    let inviterProfiles: Record<string, string> = {};
    if (inviterIds.length > 0) {
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, display_name")
        .in("id", inviterIds);
      if (profiles) {
        inviterProfiles = profiles.reduce((acc, p) => {
          acc[p.id] = p.display_name || '';
          return acc;
        }, {} as Record<string, string>);
      }
    }

    return filteredData.map(request => ({
      ...request,
      inviter_name: request.invited_by_user_id ? inviterProfiles[request.invited_by_user_id] : null
    }));
  };

  const { data: ownerRequests, isLoading: ownerLoading } = useQuery({
    queryKey: ["joinRequests", "owner"],
    queryFn: () => fetchJoinRequests(true),
  });

  const { data: recommendRequests, isLoading: recommendLoading } = useQuery({
    queryKey: ["joinRequests", "recommend"],
    queryFn: () => fetchJoinRequests(false),
  });

  const { data: emailConfig } = useQuery({
    queryKey: ["emailConfig", "join_request"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("email_config")
        .select("*")
        .eq("type", "join_request")
        .single();

      if (error) throw error;
      return data;
    },
  });

  const { data: siteSettings } = useQuery({
    queryKey: ["siteSettings"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("site_settings")
        .select("logo_url")
        .single();

      if (error) throw error;
      return data;
    },
  });

  // Realtime subscription for join_requests status updates
  useEffect(() => {
    const channel = supabase
      .channel('join_requests_changes')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'join_requests'
        },
        () => {
          queryClient.invalidateQueries({ queryKey: ["joinRequests"] });
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [queryClient]);

  // Derive current data based on active tab
  const joinRequests = activeTab === "owner" ? ownerRequests : recommendRequests;
  const isLoading = activeTab === "owner" ? ownerLoading : recommendLoading;

  const filteredRequests = joinRequests?.filter((request) => {
    const searchLower = search.toLowerCase();
    const matchesSearch = 
      request.name.toLowerCase().includes(searchLower) ||
      request.email.toLowerCase().includes(searchLower) ||
      request.restaurant_name.toLowerCase().includes(searchLower) ||
      request.phone.toLowerCase().includes(searchLower);
    
    const matchesStatus = statusFilter === "all" || request.status === statusFilter;
    const matchesTaxStatus = taxStatusFilter === "all" || (request as any).tax_verification_status === taxStatusFilter;
    const matchesArchived = showArchived || !(request as any).archived;
    
    return matchesSearch && matchesStatus && matchesTaxStatus && matchesArchived;
  });

  const archiveMutation = useMutation({
    mutationFn: async ({ id, archived }: { id: string; archived: boolean }) => {
      const { error } = await supabase
        .from("join_requests")
        .update({ archived } as any)
        .eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["joinRequests"] });
      toast({ title: "操作成功" });
    },
    onError: (error) => {
      toast({ title: "操作失败", description: error.message, variant: "destructive" });
    },
  });

  const handleUpdateEmail = async () => {
    const newEmail = prompt(t("joinUs.enterNewEmail"), emailConfig?.recipient_email);
    if (!newEmail) return;

    try {
      const { error } = await supabase
        .from("email_config")
        .update({ recipient_email: newEmail })
        .eq("id", emailConfig?.id);

      if (error) throw error;

      toast({
        title: t("common.success"),
        description: t("joinUs.emailUpdated"),
      });
    } catch (error) {
      console.error("Error updating email:", error);
      toast({
        title: t("common.error"),
        description: t("joinUs.emailUpdateError"),
        variant: "destructive",
      });
    }
  };

  const updateStatusMutation = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: string }) => {
      const { error } = await supabase
        .from("join_requests")
        .update({ status })
        .eq("id", id);
      
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["joinRequests"] });
      toast({
        title: t("common.success"),
        description: t("joinUs.statusUpdated"),
      });
    },
    onError: (error) => {
      console.error("Error updating status:", error);
      toast({
        title: t("common.error"),
        description: t("joinUs.statusUpdateError"),
        variant: "destructive",
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from("join_requests")
        .delete()
        .eq("id", id);
      
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["joinRequests"] });
      toast({
        title: t("common.success"),
        description: t("joinUs.requestDeleted"),
      });
      setDeleteId(null);
    },
    onError: (error) => {
      console.error("Error deleting request:", error);
      toast({
        title: t("common.error"),
        description: t("joinUs.deleteError"),
        variant: "destructive",
      });
    },
  });

  const handleExport = () => {
    if (!filteredRequests || filteredRequests.length === 0) {
      toast({
        title: t("admin.noDataToExport"),
        variant: "destructive",
      });
      return;
    }

    const csvContent = [
      ["Name", "Email", "Phone", "Restaurant Name", "Restaurant Address", "Features", "Invitation Code", "Invited By", "Status", "Submitted Date"],
      ...filteredRequests.map((request) => [
        request.name,
        request.email,
        request.phone,
        request.restaurant_name,
        request.restaurant_address || "",
        Array.isArray(request.features_selected) ? request.features_selected.join(", ") : "",
        request.invitation_code || "",
        request.inviter_name || "",
        request.status || "pending",
        new Date(request.created_at).toLocaleString(),
      ]),
    ]
      .map((row) => row.map((cell) => `"${cell}"`).join(","))
      .join("\n");

    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `join_requests_${new Date().toISOString()}.csv`);
    link.click();
    URL.revokeObjectURL(url);

    toast({
      title: t("admin.exportSuccess"),
    });
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "completed":
        return "default";
      case "received":
        return "secondary";
      case "cancelled":
        return "destructive";
      default:
        return "outline";
    }
  };

  const openEmailDialog = (request: any) => {
    setSelectedRequest(request);
    setMerchantAccount(request.email);
    setMerchantPassword("");
    setEmailOnlyMode(false);
    setEmailDialogOpen(true);
  };

  const openDetailDialog = (request: any) => {
    setSelectedRequest(request);
    setDetailDialogOpen(true);
  };

  const handleSendEmail = async () => {
    if (!selectedRequest || !merchantAccount.trim() || !merchantPassword.trim()) {
      toast({
        title: t("common.error"),
        description: t("joinUs.accountPasswordRequired"),
        variant: "destructive",
      });
      return;
    }

    // Validate password length
    if (merchantPassword.length < 6) {
      toast({
        title: t("common.error"),
        description: t("auth.passwordTooShort"),
        variant: "destructive",
      });
      return;
    }

    try {
      // Email-only mode: skip user creation
      if (emailOnlyMode) {
        setSendingEmail(true);
        
        const emailSubject = `【小熊市场】您的商家账号信息 - ${selectedRequest.restaurant_name}`;
        const emailContent = `您的商家账号信息如下！`;

        const { data, error } = await supabase.functions.invoke("send-merchant-email", {
          body: {
            to: selectedRequest.email,
            subject: emailSubject,
            content: emailContent,
            merchantName: selectedRequest.name,
            account: merchantAccount,
            password: merchantPassword,
            logoUrl: siteSettings?.logo_url || null,
          },
        });

        if (error) throw error;
        if (!data.success) throw new Error(data.error);

        // Update email_sent_at after email sent successfully
        await supabase
          .from("join_requests")
          .update({ 
            email_sent_at: new Date().toISOString()
          })
          .eq("id", selectedRequest.id);

        queryClient.invalidateQueries({ queryKey: ["joinRequests"] });

        toast({
          title: t("common.success"),
          description: t("joinUs.emailSentSuccess"),
        });
        setEmailDialogOpen(false);
        return;
      }

      // Create user mode
      setCreatingUser(true);
      
      // Step 1: Create merchant user first
      const { data: sessionData } = await supabase.auth.getSession();
      
      // Verify session exists
      if (!sessionData?.session) {
        toast({
          title: t("common.error"),
          description: t("auth.sessionExpired"),
          variant: "destructive",
        });
        setCreatingUser(false);
        return;
      }

      const { data: createData, error: createError } = await supabase.functions.invoke("admin-create-user", {
        body: {
          email: merchantAccount,
          password: merchantPassword,
          displayName: selectedRequest.name,
          phone: selectedRequest.phone,
          role: "merchant",
        },
      });

      // Check for network/function invocation error
      if (createError) {
        console.error("Create user function error:", createError);
        toast({
          title: t("common.error"),
          description: createError.message || t("admin.createUserError"),
          variant: "destructive",
        });
        setCreatingUser(false);
        return;
      }

      // Check for business logic error returned from edge function
      if (createData?.error) {
        console.error("Create user business error:", createData.error);
        toast({
          title: t("common.error"),
          description: createData.error,
          variant: "destructive",
        });
        setCreatingUser(false);
        return;
      }

      // Verify user was actually created
      if (!createData?.success || !createData?.user) {
        console.error("User creation failed - no user returned");
        toast({
          title: t("common.error"),
          description: t("admin.createUserError"),
          variant: "destructive",
        });
        setCreatingUser(false);
        return;
      }

      toast({
        title: t("common.success"),
        description: t("joinUs.merchantUserCreated"),
      });

      setCreatingUser(false);
      setSendingEmail(true);

      // Step 2: Send email to merchant (only if user creation succeeded)
      const emailSubject = `【小熊市场】您的商家账号已创建 - ${selectedRequest.restaurant_name}`;
      const emailContent = `您的商家账号已创建成功！`;

      const { data, error } = await supabase.functions.invoke("send-merchant-email", {
        body: {
          to: selectedRequest.email,
          subject: emailSubject,
          content: emailContent,
          merchantName: selectedRequest.name,
          account: merchantAccount,
          password: merchantPassword,
          logoUrl: siteSettings?.logo_url || null,
        },
      });

      if (error) throw error;
      if (!data.success) throw new Error(data.error);

      // Update status to "received" and record email_sent_at after email sent successfully
      await supabase
        .from("join_requests")
        .update({ 
          status: "received",
          email_sent_at: new Date().toISOString()
        })
        .eq("id", selectedRequest.id);

      queryClient.invalidateQueries({ queryKey: ["joinRequests"] });

      toast({
        title: t("common.success"),
        description: t("joinUs.emailSentSuccess"),
      });
      setEmailDialogOpen(false);
    } catch (error: any) {
      console.error("Error:", error);
      toast({
        title: t("common.error"),
        description: error.message || t("joinUs.emailSendError"),
        variant: "destructive",
      });
    } finally {
      setCreatingUser(false);
      setSendingEmail(false);
    }
  };

  return (
    <>
      <div className="space-y-6">
        <div>
          <h2 className="text-3xl font-bold">{t("joinUs.adminTitle")}</h2>
          <p className="text-muted-foreground mt-2">{t("joinUs.adminDescription")}</p>
        </div>

        <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
          <TabsList className="grid w-full grid-cols-2">
            <TabsTrigger value="owner" className="gap-2">
              <Store className="w-4 h-4" />
              店主申请
              {ownerRequests && ownerRequests.length > 0 && (
                <Badge variant="secondary" className="ml-1">{ownerRequests.length}</Badge>
              )}
            </TabsTrigger>
            <TabsTrigger value="recommend" className="gap-2">
              <Send className="w-4 h-4" />
              推荐商店
              {recommendRequests && recommendRequests.length > 0 && (
                <Badge variant="secondary" className="ml-1">{recommendRequests.length}</Badge>
              )}
            </TabsTrigger>
          </TabsList>

          <TabsContent value={activeTab} className="mt-4 space-y-4">

        <div className="grid gap-4 md:grid-cols-2">
          <Card>
            <CardHeader>
              <CardTitle>{t("joinUs.recipientEmail")}</CardTitle>
              <CardDescription>{t("joinUs.recipientEmailDesc")}</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-4">
                <Input value={emailConfig?.recipient_email || ""} readOnly />
                <Button onClick={handleUpdateEmail}>{t("common.edit")}</Button>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>{t("joinUs.totalRequests")}</CardTitle>
              <CardDescription>{t("joinUs.totalRequestsDesc")}</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="text-3xl font-bold">{joinRequests?.length || 0}</div>
            </CardContent>
          </Card>
        </div>

        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <div>
                <CardTitle>{t("joinUs.allRequests")}</CardTitle>
                <CardDescription>{t("joinUs.allRequestsDesc")}</CardDescription>
              </div>
              <Button onClick={handleExport} variant="outline">
                <Download className="w-4 h-4 mr-2" />
                {t("admin.exportCSV")}
              </Button>
            </div>
            <div className="flex items-center gap-4 mt-4">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input
                  placeholder={t("joinUs.searchPlaceholder")}
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="pl-10"
                />
              </div>
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" className="gap-2">
                    <Filter className="w-4 h-4" />
                    {statusFilter === "all" 
                      ? t("admin.allStatus") 
                      : t(`joinUs.status.${statusFilter}`)}
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="bg-background">
                  <DropdownMenuItem onClick={() => setStatusFilter("all")}>
                    {t("admin.allStatus")}
                  </DropdownMenuItem>
                  {STATUS_OPTIONS.map((status) => (
                    <DropdownMenuItem key={status} onClick={() => setStatusFilter(status)}>
                      {t(`joinUs.status.${status}`)}
                    </DropdownMenuItem>
                  ))}
                </DropdownMenuContent>
              </DropdownMenu>
              <div className="flex items-center gap-2">
                <Switch
                  id="showArchived"
                  checked={showArchived}
                  onCheckedChange={setShowArchived}
                />
                <Label htmlFor="showArchived" className="text-sm text-muted-foreground cursor-pointer whitespace-nowrap">
                  显示已归档
                </Label>
              </div>
            </div>
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <div className="text-center py-8 text-muted-foreground">{t("common.loading")}</div>
            ) : filteredRequests && filteredRequests.length > 0 ? (
              <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {filteredRequests.map((request) => (
                  <Card key={request.id} className="relative overflow-hidden hover:shadow-md transition-shadow">
                    {/* Status badge & merchant type at top right */}
                    <div className="absolute top-3 right-3 flex items-center gap-1.5">
                      {(request as any).archived && (
                        <Badge variant="outline" className="text-xs">
                          <Archive className="w-3 h-3 mr-1" />已归档
                        </Badge>
                      )}
                      {request.merchant_type === 'claim' ? (
                        <Badge variant="outline" className="text-xs bg-amber-50 text-amber-700 border-amber-200 dark:bg-amber-950 dark:text-amber-300 dark:border-amber-800">
                          认领商店
                        </Badge>
                      ) : request.merchant_type === 'shallow' ? (
                        <Badge variant="outline" className="text-xs bg-blue-50 text-blue-700 border-blue-200 dark:bg-blue-950 dark:text-blue-300 dark:border-blue-800">
                          创建商店
                        </Badge>
                      ) : null}
                      <Badge variant={getStatusColor(request.status || "pending")}>
                        {t(`joinUs.status.${request.status || "pending"}`)}
                      </Badge>
                    </div>
                    
                    <CardContent className="pt-6">
                      {/* Header: Name & Restaurant */}
                      <div className="mb-4">
                        <h3 className="font-semibold text-lg truncate pr-20">{request.name}</h3>
                        <div className="flex items-center gap-2 text-sm text-muted-foreground mt-1">
                          <Store className="w-3.5 h-3.5 flex-shrink-0" />
                          <span className="truncate">{request.restaurant_name}</span>
                        </div>
                      </div>
                      
                      {/* Contact info */}
                      <div className="space-y-2 mb-4">
                        <div className="flex items-center gap-2 text-sm">
                          <Mail className="w-3.5 h-3.5 text-muted-foreground flex-shrink-0" />
                          <span className="truncate">{request.email}</span>
                        </div>
                        <div className="flex items-center gap-2 text-sm">
                          <Phone className="w-3.5 h-3.5 text-muted-foreground flex-shrink-0" />
                          <span>{request.phone}</span>
                        </div>
                      </div>
                      
                      {/* Time & Invitation code */}
                      <div className="flex items-center justify-between text-xs text-muted-foreground mb-4">
                        <div className="flex items-center gap-1.5">
                          <Clock className="w-3 h-3" />
                          <span>{formatDistanceToNow(new Date(request.created_at), { addSuffix: true })}</span>
                        </div>
                        {request.invitation_code && (
                          <div className="flex items-center gap-1.5">
                            <Ticket className="w-3 h-3" />
                            <code className="text-xs bg-muted px-1 py-0.5 rounded">{request.invitation_code}</code>
                          </div>
                        )}
                      </div>
                      
                      {/* AI verification status */}
                      {request.ai_verification_status && (
                        <div className={`flex items-center gap-1.5 text-xs mb-2 ${
                          request.ai_verification_status === 'verified' ? 'text-green-600 dark:text-green-400' :
                          request.ai_verification_status === 'rejected' ? 'text-red-600 dark:text-red-400' :
                          'text-yellow-600 dark:text-yellow-400'
                        }`}>
                          {request.ai_verification_status === 'verified' ? (
                            <><CheckCircle2 className="w-3 h-3" /><span>AI验证通过</span></>
                          ) : request.ai_verification_status === 'rejected' ? (
                            <><Trash2 className="w-3 h-3" /><span>AI验证未通过</span></>
                          ) : (
                            <><Clock className="w-3 h-3" /><span>AI验证中...</span></>
                          )}
                        </div>
                       )}
                      
                      {/* Tax ID verification status */}
                      {request.tax_id && (
                        <div className={`flex items-center gap-1.5 text-xs mb-2 ${
                          (request as any).tax_verification_status === 'verified' ? 'text-green-600 dark:text-green-400' :
                          (request as any).tax_verification_status === 'rejected' ? 'text-red-600 dark:text-red-400' :
                          (request as any).tax_verification_status === 'manual_review' ? 'text-amber-600 dark:text-amber-400' :
                          'text-muted-foreground'
                        }`}>
                          {(request as any).tax_verification_status === 'verified' ? (
                            <><CheckCircle2 className="w-3 h-3" /><span>税号验证通过</span></>
                          ) : (request as any).tax_verification_status === 'rejected' ? (
                            <><Trash2 className="w-3 h-3" /><span>税号不匹配</span></>
                          ) : (request as any).tax_verification_status === 'manual_review' ? (
                            <><Clock className="w-3 h-3" /><span>待人工审核 (税号: {request.tax_id})</span></>
                          ) : (
                            <><Clock className="w-3 h-3" /><span>税号: {request.tax_id}</span></>
                          )}
                        </div>
                      )}

                      {/* Email sent indicator */}
                      {request.email_sent_at && (
                        <div className="flex items-center gap-1.5 text-xs text-green-600 dark:text-green-400 mb-4">
                          <CheckCircle2 className="w-3 h-3" />
                          <span>{t("joinUs.emailSent", "邮件已发送")}</span>
                        </div>
                      )}
                      
                      <Separator className="my-3" />
                      
                      {/* Action buttons */}
                      <div className="flex items-center gap-2">
                        <Button
                          size="sm"
                          variant="outline"
                          className="flex-1"
                          onClick={() => openDetailDialog(request)}
                        >
                          <Eye className="w-4 h-4 mr-1.5" />
                          {t("common.viewDetails", "查看详情")}
                        </Button>
                        <Button
                          size="sm"
                          variant={(request as any).archived ? "secondary" : "outline"}
                          onClick={() => archiveMutation.mutate({ id: request.id, archived: !(request as any).archived })}
                          disabled={archiveMutation.isPending}
                          title={(request as any).archived ? "取消归档" : "归档"}
                        >
                          <Archive className="w-4 h-4" />
                        </Button>
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button size="sm" variant="outline">
                              <MoreHorizontal className="w-4 h-4" />
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent align="end" className="bg-background">
                            <DropdownMenuItem onClick={() => openEmailDialog(request)}>
                              <Send className="w-4 h-4 mr-2" />
                              {t("joinUs.sendEmail")}
                            </DropdownMenuItem>
                            <DropdownMenuItem
                              className="text-destructive focus:text-destructive"
                              onClick={() => setDeleteId(request.id)}
                            >
                              <Trash2 className="w-4 h-4 mr-2" />
                              {t("common.delete")}
                            </DropdownMenuItem>
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            ) : (
              <div className="text-center py-8 text-muted-foreground">{t("joinUs.noRequests")}</div>
            )}
          </CardContent>
        </Card>

          </TabsContent>
        </Tabs>
      </div>

      {/* Detail Dialog */}
      <Dialog open={detailDialogOpen} onOpenChange={setDetailDialogOpen}>
        <DialogContent className="sm:max-w-[600px] max-h-[85vh]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Store className="w-5 h-5" />
              {selectedRequest?.restaurant_name}
            </DialogTitle>
            <DialogDescription>
              {t("joinUs.requestDetail", "申请详情")}
            </DialogDescription>
          </DialogHeader>
          
          <ScrollArea className="max-h-[60vh] pr-4">
            {selectedRequest && (
              <div className="space-y-6">
                {/* Status */}
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium text-muted-foreground">{t("joinUs.status")}</span>
                  <Select
                    value={selectedRequest.status || "pending"}
                    onValueChange={(value) => {
                      updateStatusMutation.mutate({ id: selectedRequest.id, status: value });
                      setSelectedRequest({ ...selectedRequest, status: value });
                    }}
                    disabled={updateStatusMutation.isPending}
                  >
                    <SelectTrigger className="w-[150px]">
                      <SelectValue>
                        <Badge variant={getStatusColor(selectedRequest.status || "pending")}>
                          {t(`joinUs.status.${selectedRequest.status || "pending"}`)}
                        </Badge>
                      </SelectValue>
                    </SelectTrigger>
                    <SelectContent>
                      {STATUS_OPTIONS.map((status) => (
                        <SelectItem key={status} value={status}>
                          <Badge variant={getStatusColor(status)}>
                            {t(`joinUs.status.${status}`)}
                          </Badge>
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                
                {/* Merchant Type & AI Verification */}
                {selectedRequest.merchant_type === 'shallow' && (
                  <div className="rounded-lg border p-4 space-y-3">
                    <div className="flex items-center justify-between">
                      <span className="text-sm font-medium">商家类型</span>
                      <Badge variant="outline" className="bg-blue-50 text-blue-700 border-blue-200 dark:bg-blue-950 dark:text-blue-300 dark:border-blue-800">
                        浅层商家（免费入驻）
                      </Badge>
                    </div>
                    {selectedRequest.ai_verification_status && (
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium">AI验证状态</span>
                        <Badge variant={
                          selectedRequest.ai_verification_status === 'verified' ? 'default' :
                          selectedRequest.ai_verification_status === 'rejected' ? 'destructive' : 'outline'
                        }>
                          {selectedRequest.ai_verification_status === 'verified' ? '✅ 验证通过' :
                           selectedRequest.ai_verification_status === 'rejected' ? '❌ 验证未通过' : '⏳ 验证中'}
                        </Badge>
                      </div>
                    )}
                    {selectedRequest.ai_verification_result && (
                      <div className="text-xs text-muted-foreground bg-muted p-3 rounded">
                        <p className="font-medium mb-1">AI验证详情：</p>
                        <p>置信度: {(selectedRequest.ai_verification_result as any)?.confidence ?? 'N/A'}</p>
                        <p>原因: {(selectedRequest.ai_verification_result as any)?.reason ?? 'N/A'}</p>
                      </div>
                    )}
                  </div>
                )}
                
                {/* Tax ID Verification Section */}
                {selectedRequest.tax_id && (
                  <div className="rounded-lg border p-4 space-y-3">
                    <div className="flex items-center justify-between">
                      <span className="text-sm font-medium">税卡号 (NIF/VAT)</span>
                      <code className="text-sm bg-muted px-2 py-1 rounded">{selectedRequest.tax_id}</code>
                    </div>
                    <div className="flex items-center justify-between">
                      <span className="text-sm font-medium">税号验证状态</span>
                      <Badge variant={
                        (selectedRequest as any).tax_verification_status === 'verified' ? 'default' :
                        (selectedRequest as any).tax_verification_status === 'rejected' ? 'destructive' : 
                        (selectedRequest as any).tax_verification_status === 'manual_review' ? 'outline' : 'secondary'
                      }>
                        {(selectedRequest as any).tax_verification_status === 'verified' ? '✅ 自动验证通过' :
                         (selectedRequest as any).tax_verification_status === 'rejected' ? '❌ 税号不匹配' : 
                         (selectedRequest as any).tax_verification_status === 'manual_review' ? '⚠️ 待人工审核' : '⏳ 待验证'}
                      </Badge>
                    </div>
                    {(selectedRequest as any).tax_verification_result && (
                      <div className="text-xs text-muted-foreground bg-muted p-3 rounded space-y-1">
                        <p className="font-medium mb-1">税号验证详情：</p>
                        <p>国家: {(selectedRequest as any).tax_verification_result?.country_name ?? 'N/A'}</p>
                        <p>公司名: {(selectedRequest as any).tax_verification_result?.ai_analysis?.company_name ?? 'N/A'}</p>
                        <p>置信度: {(selectedRequest as any).tax_verification_result?.ai_analysis?.confidence ?? 'N/A'}%</p>
                        <p>分析: {(selectedRequest as any).tax_verification_result?.ai_analysis?.reason ?? 'N/A'}</p>
                        {(selectedRequest as any).tax_verification_result?.vies_result && (
                          <div className="mt-2 pt-2 border-t border-border">
                            <p className="font-medium">VIES VAT 验证:</p>
                            <p>有效: {(selectedRequest as any).tax_verification_result.vies_result.valid ? '是' : '否'}</p>
                            {(selectedRequest as any).tax_verification_result.vies_result.name && (
                              <p>注册名: {(selectedRequest as any).tax_verification_result.vies_result.name}</p>
                            )}
                          </div>
                        )}
                      </div>
                    )}
                    {/* Manual approve/reject buttons for manual_review status */}
                    {(selectedRequest as any).tax_verification_status === 'manual_review' && (
                      <div className="flex gap-2 pt-2">
                        <Button
                          size="sm"
                          onClick={async () => {
                            try {
                              const { data, error } = await supabase.functions.invoke("approve-store-claim", {
                                body: { join_request_id: selectedRequest.id, action: "approve" },
                              });
                              if (error) throw error;
                              if (data?.error) throw new Error(data.error);
                              queryClient.invalidateQueries({ queryKey: ["joinRequests"] });
                              setSelectedRequest({ ...selectedRequest, tax_verification_status: 'verified', status: 'completed' });
                              toast({ title: "已批准", description: "认领已批准，用户已升级为商家，商店已关联" });
                            } catch (e: any) {
                              toast({ title: "批准失败", description: e.message, variant: "destructive" });
                            }
                          }}
                          className="flex-1"
                        >
                          <CheckCircle2 className="w-4 h-4 mr-1" /> 批准认领
                        </Button>
                        <Button
                          size="sm"
                          variant="destructive"
                          onClick={async () => {
                            try {
                              const { data, error } = await supabase.functions.invoke("approve-store-claim", {
                                body: { join_request_id: selectedRequest.id, action: "reject" },
                              });
                              if (error) throw error;
                              if (data?.error) throw new Error(data.error);
                              queryClient.invalidateQueries({ queryKey: ["joinRequests"] });
                              setSelectedRequest({ ...selectedRequest, tax_verification_status: 'rejected' });
                              toast({ title: "已拒绝", description: "税号验证已手动拒绝" });
                            } catch (e: any) {
                              toast({ title: "拒绝失败", description: e.message, variant: "destructive" });
                            }
                          }}
                          className="flex-1"
                        >
                          <Trash2 className="w-4 h-4 mr-1" /> 拒绝认领
                        </Button>
                      </div>
                    )}
                  </div>
                )}

                <Separator />
                
                {/* Contact Info Section */}
                <div>
                  <h4 className="font-medium mb-3">{t("joinUs.contactInfo", "联系信息")}</h4>
                  <div className="space-y-3">
                    <div className="flex items-start gap-3">
                      <UserCircle className="w-4 h-4 text-muted-foreground mt-0.5" />
                      <div>
                        <p className="text-sm font-medium">{selectedRequest.name}</p>
                        <p className="text-xs text-muted-foreground">{t("joinUs.name")}</p>
                      </div>
                    </div>
                    <div className="flex items-start gap-3">
                      <Mail className="w-4 h-4 text-muted-foreground mt-0.5" />
                      <div>
                        <a href={`mailto:${selectedRequest.email}`} className="text-sm font-medium hover:underline">
                          {selectedRequest.email}
                        </a>
                        <p className="text-xs text-muted-foreground">{t("joinUs.email")}</p>
                      </div>
                    </div>
                    <div className="flex items-start gap-3">
                      <Phone className="w-4 h-4 text-muted-foreground mt-0.5" />
                      <div>
                        <a href={`tel:${selectedRequest.phone}`} className="text-sm font-medium hover:underline">
                          {selectedRequest.phone}
                        </a>
                        <p className="text-xs text-muted-foreground">{t("joinUs.phone")}</p>
                      </div>
                    </div>
                  </div>
                </div>
                
                <Separator />
                
                {/* Restaurant Info Section */}
                <div>
                  <h4 className="font-medium mb-3">{t("joinUs.restaurantInfo", "餐厅信息")}</h4>
                  <div className="space-y-3">
                    <div className="flex items-start gap-3">
                      <Store className="w-4 h-4 text-muted-foreground mt-0.5" />
                      <div>
                        <p className="text-sm font-medium">{selectedRequest.restaurant_name}</p>
                        <p className="text-xs text-muted-foreground">{t("joinUs.restaurantName")}</p>
                      </div>
                    </div>
                    {selectedRequest.restaurant_address && (
                      <div className="flex items-start gap-3">
                        <MapPin className="w-4 h-4 text-muted-foreground mt-0.5" />
                        <div>
                          <p className="text-sm font-medium">{selectedRequest.restaurant_address}</p>
                          <p className="text-xs text-muted-foreground">{t("joinUs.restaurantAddress")}</p>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
                
                <Separator />
                
                
                {/* Invitation Code Section */}
                {selectedRequest.invitation_code && (
                  <>
                    <Separator />
                    <div>
                      <h4 className="font-medium mb-3">{t("joinUs.invitationCode", "邀请码")}</h4>
                      <div className="space-y-2">
                        <div className="flex items-center gap-2">
                          <Ticket className="w-4 h-4 text-muted-foreground" />
                          <code className="text-sm bg-muted px-2 py-1 rounded">
                            {selectedRequest.invitation_code}
                          </code>
                        </div>
                        {selectedRequest.inviter_name && (
                          <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <UserCircle className="w-4 h-4" />
                            {t("joinUs.invitedBy", "邀请人")}: {selectedRequest.inviter_name}
                          </div>
                        )}
                      </div>
                    </div>
                  </>
                )}
                
                <Separator />
                
                {/* Timestamps Section */}
                <div>
                  <h4 className="font-medium mb-3">{t("joinUs.timestamps", "时间信息")}</h4>
                  <div className="space-y-2 text-sm">
                    <div className="flex items-center justify-between">
                      <span className="text-muted-foreground">{t("joinUs.submittedAt")}</span>
                      <span>{format(new Date(selectedRequest.created_at), "yyyy-MM-dd HH:mm")}</span>
                    </div>
                    {selectedRequest.email_sent_at && (
                      <div className="flex items-center justify-between">
                        <span className="text-muted-foreground">{t("joinUs.emailSentAt", "邮件发送时间")}</span>
                        <div className="flex items-center gap-1.5 text-green-600 dark:text-green-400">
                          <CheckCircle2 className="w-3.5 h-3.5" />
                          <span>{format(new Date(selectedRequest.email_sent_at), "yyyy-MM-dd HH:mm")}</span>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </ScrollArea>
          
          {/* Approve/Reject buttons - show when not yet completed */}
          {selectedRequest && selectedRequest.status !== 'completed' && (selectedRequest as any).tax_verification_status !== 'verified' && (
            <div className="flex gap-2 w-full pb-2">
              <Button
                className="flex-1"
                disabled={approvingId === selectedRequest?.id}
                onClick={async () => {
                  try {
                    setApprovingId(selectedRequest.id);
                    const { data, error } = await supabase.functions.invoke("approve-store-claim", {
                      body: { join_request_id: selectedRequest.id, action: "approve" },
                    });
                    if (error) throw error;
                    if (data?.error) throw new Error(data.error);
                    queryClient.invalidateQueries({ queryKey: ["joinRequests"] });
                    setSelectedRequest({ ...selectedRequest, tax_verification_status: 'verified', status: 'completed' });
                    toast({ title: "已批准", description: "申请已通过，商店已创建并关联用户" });
                  } catch (e: any) {
                    toast({ title: "批准失败", description: e.message, variant: "destructive" });
                  } finally {
                    setApprovingId(null);
                  }
                }}
              >
                <CheckCircle2 className="w-4 h-4 mr-1.5" />
                {approvingId === selectedRequest?.id ? "处理中..." : "通过"}
              </Button>
              <Button
                variant="destructive"
                className="flex-1"
                disabled={approvingId === selectedRequest?.id}
                onClick={async () => {
                  try {
                    setApprovingId(selectedRequest.id);
                    const { data, error } = await supabase.functions.invoke("approve-store-claim", {
                      body: { join_request_id: selectedRequest.id, action: "reject" },
                    });
                    if (error) throw error;
                    if (data?.error) throw new Error(data.error);
                    queryClient.invalidateQueries({ queryKey: ["joinRequests"] });
                    setSelectedRequest({ ...selectedRequest, tax_verification_status: 'rejected' });
                    toast({ title: "已拒绝", description: "申请已被拒绝" });
                  } catch (e: any) {
                    toast({ title: "拒绝失败", description: e.message, variant: "destructive" });
                  } finally {
                    setApprovingId(null);
                  }
                }}
              >
                <XCircle className="w-4 h-4 mr-1.5" />
                不通过
              </Button>
            </div>
          )}

          {/* Already approved indicator */}
          {selectedRequest && ((selectedRequest as any).tax_verification_status === 'verified' || selectedRequest.status === 'completed') && (
            <div className="flex items-center gap-2 text-sm text-green-600 dark:text-green-400 w-full pb-2">
              <CheckCircle2 className="w-4 h-4" />
              <span>已通过审核</span>
            </div>
          )}

          <DialogFooter className="flex-row gap-2 sm:justify-between">
            <Button
              variant="outline"
              onClick={() => {
                setDetailDialogOpen(false);
                openEmailDialog(selectedRequest);
              }}
            >
              <Send className="w-4 h-4 mr-2" />
              {t("joinUs.sendEmail")}
            </Button>
            <Button onClick={() => setDetailDialogOpen(false)}>
              {t("common.close", "关闭")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <AlertDialog open={deleteId !== null} onOpenChange={(open) => !open && setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t("joinUs.confirmDelete")}</AlertDialogTitle>
            <AlertDialogDescription>
              {t("joinUs.confirmDeleteDescription")}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => deleteId && deleteMutation.mutate(deleteId)}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {t("common.delete")}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <Dialog open={emailDialogOpen} onOpenChange={setEmailDialogOpen}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle>{t("joinUs.sendAccountTitle")}</DialogTitle>
            <DialogDescription>
              {t("joinUs.sendAccountDescription", { name: selectedRequest?.name })}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="flex items-center justify-between p-3 bg-muted rounded-lg">
              <div className="space-y-0.5">
                <Label htmlFor="emailOnlyMode" className="font-medium">{t("joinUs.emailOnlyMode")}</Label>
                <p className="text-xs text-muted-foreground">{t("joinUs.emailOnlyModeDesc")}</p>
              </div>
              <Switch
                id="emailOnlyMode"
                checked={emailOnlyMode}
                onCheckedChange={setEmailOnlyMode}
              />
            </div>
            
            {!emailOnlyMode && (
              <div className="p-3 bg-blue-50 dark:bg-blue-950 border border-blue-200 dark:border-blue-800 rounded-lg">
                <p className="text-sm text-blue-700 dark:text-blue-300">
                  ℹ️ {t("joinUs.createUserModeNote")}
                </p>
              </div>
            )}
            
            <div className="space-y-2">
              <Label>{t("joinUs.emailRecipient")}</Label>
              <Input value={selectedRequest?.email || ""} disabled />
            </div>
            <div className="space-y-2">
              <Label htmlFor="account">{t("joinUs.merchantAccount")}</Label>
              <Input
                id="account"
                value={merchantAccount}
                onChange={(e) => setMerchantAccount(e.target.value)}
                placeholder={t("joinUs.merchantAccountPlaceholder")}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="password">{t("joinUs.merchantPassword")}</Label>
              <Input
                id="password"
                type="text"
                value={merchantPassword}
                onChange={(e) => setMerchantPassword(e.target.value)}
                placeholder={t("joinUs.merchantPasswordPlaceholder")}
              />
            </div>
            <div className="p-3 bg-amber-50 dark:bg-amber-950 border border-amber-200 dark:border-amber-800 rounded-lg">
              <p className="text-sm text-amber-700 dark:text-amber-300">
                ⚠️ {t("joinUs.passwordSecurityNote")}
              </p>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setEmailDialogOpen(false)} disabled={creatingUser || sendingEmail}>
              {t("common.cancel")}
            </Button>
            <Button onClick={handleSendEmail} disabled={creatingUser || sendingEmail}>
              {creatingUser 
                ? t("joinUs.creatingUser") 
                : sendingEmail 
                  ? t("common.sending") 
                  : emailOnlyMode 
                    ? t("joinUs.sendEmailOnly")
                    : t("joinUs.createAndSendEmail")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
};

export default AdminJoinRequests;
